-- Quiz Storytelling — 8 quiz de module + 1 quiz de validation finale.-- Généré par scripts/generate_story_quizzes.py à partir du doc client.-- Même modèle que Personal Branding / Muslim Mindset : quiz attachés aux chapitres.SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Storytelling — Module 1 — Fondements & Neuroscience", "description": "25 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Qu'est-ce que le storytelling ?", "options": ["L'art d'inventer des histoires fictives", "L'art de raconter des histoires pour transmettre un message et provoquer une action", "Une technique de manipulation marketing", "Un style d'écriture littéraire"], "correct_index": 1, "explication": ""}, {"question": "Combien de zones du cerveau s'activent quand on lit une histoire ?", "options": ["2 zones", "4 zones", "7 zones", "12 zones"], "correct_index": 2, "explication": ""}, {"question": "Combien de zones du cerveau s'activent quand on lit des données simples ?", "options": ["1 zone", "2 zones", "5 zones", "7 zones"], "correct_index": 1, "explication": ""}, {"question": "Selon l'étude de Stanford, une histoire est combien de fois plus mémorable qu'un fait brut ?", "options": ["5 fois", "10 fois", "22 fois", "50 fois"], "correct_index": 2, "explication": ""}, {"question": "Quel phénomène se produit quand le cerveau du narrateur et du lecteur se synchronisent ?", "options": ["L'effet miroir", "Le couplage neuronal (neural coupling)", "La dissonance cognitive", "L'empathie passive"], "correct_index": 1, "explication": ""}, {"question": "Quelle hormone est libérée par une histoire engageante et crée la confiance ?", "options": ["Dopamine", "Cortisol", "Adrénaline", "Ocytocine"], "correct_index": 3, "explication": ""}, {"question": "Quelle hormone maintient l'attention focalisée grâce au suspense ?", "options": ["Ocytocine", "Dopamine", "Cortisol", "Sérotonine"], "correct_index": 2, "explication": ""}, {"question": "Quelle hormone est libérée par un dénouement positif et crée un souvenir fort ?", "options": ["Cortisol", "Ocytocine", "Dopamine", "Adrénaline"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la règle fondamentale du storytelling ?", "options": ["Les histoires divertissent", "Les faits convainquent mieux", "Les faits informent, les histoires transforment", "Le storytelling remplace la communication"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la fonction MÉMORIELLE du storytelling ?", "options": ["Convaincre sans en avoir l'air", "Créer de l'empathie", "Faire rester l'histoire en mémoire long terme", "Fédérer une communauté"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la fonction PERSUASIVE du storytelling ?", "options": ["Toucher les émotions", "Contourner les défenses rationnelles du cerveau", "Créer un souvenir durable", "Créer de l'appartenance"], "correct_index": 1, "explication": ""}, {"question": "Quelle fonction du storytelling utilise l'idée « Nous sommes ceux qui... » ?", "options": ["Mémorielle", "Émotionnelle", "Persuasive", "Identitaire"], "correct_index": 3, "explication": ""}, {"question": "En combien de temps les faits bruts s'effacent-ils de la mémoire ?", "options": ["24h", "72h", "1 semaine", "1 mois"], "correct_index": 1, "explication": ""}, {"question": "Quel est le NIVEAU 1 d'une histoire ?", "options": ["L'émotion et le conflit", "Les événements et les faits (la surface)", "Le thème profond", "La morale de l'histoire"], "correct_index": 1, "explication": ""}, {"question": "Quel est le NIVEAU 2 d'une histoire ?", "options": ["La chronologie des faits", "Le sens profond", "L'enjeu : émotion + conflit", "La structure narrative"], "correct_index": 2, "explication": ""}, {"question": "Quel est le NIVEAU 3 d'une histoire ?", "options": ["Les détails sensoriels", "Les personnages", "Le sens : la vérité universelle", "Le hook"], "correct_index": 2, "explication": ""}, {"question": "Quelle est l'erreur classique des débutants en storytelling ?", "options": ["Trop d'émotions", "Rester uniquement au Niveau 1 (les faits)", "Trop de détails sensoriels", "Des histoires trop longues"], "correct_index": 1, "explication": ""}, {"question": "Quelle est la différence entre storytelling et communication classique ?", "options": ["Le storytelling est plus long", "La communication classique est plus émotionnelle", "Le storytelling parle au cœur d'abord, la communication classique au cerveau rationnel", "Il n'y a pas de différence"], "correct_index": 2, "explication": ""}, {"question": "À quoi sert de se demander « quelle fonction je cherche à activer ? » avant de raconter ?", "options": ["À choisir la longueur du texte", "À adapter son histoire à l'objectif visé", "À choisir la plateforme de publication", "À décider du ton"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi le storytelling est-il un « avantage compétitif absolu » ?", "options": ["Parce qu'il est gratuit", "Parce que les concurrents n'utilisent que des faits et des chiffres", "Parce qu'il active 7 zones du cerveau et crée des souvenirs durables", "Parce qu'il est à la mode"], "correct_index": 2, "explication": ""}, {"question": "Quel cerveau prend les décisions d'achat selon la neuroscience ?", "options": ["Le néocortex (logique)", "Le cerveau limbique (émotions)", "Le cervelet", "Le tronc cérébral"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi dit-on que le storytelling est un « cheval de Troie émotionnel » ?", "options": ["Parce qu'il est d'origine grecque", "Parce qu'il entre par les émotions et contourne les défenses rationnelles", "Parce qu'il cache la vérité", "Parce qu'il surprend toujours"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce qui distingue une anecdote d'une histoire puissante ?", "options": ["La longueur", "Le nombre de personnages", "La présence des 3 niveaux : surface + enjeu + sens", "Le vocabulaire utilisé"], "correct_index": 2, "explication": ""}, {"question": "Pourquoi les détails concrets (« vendredi à 17h, par email ») renforcent une histoire ?", "options": ["Ils allongent le texte", "Ils activent les zones sensorielles du cerveau et créent des images mentales", "Ils sont plus professionnels", "Ils ajoutent de la crédibilité juridique"], "correct_index": 1, "explication": ""}, {"question": "Quelle est la meilleure manière d'appliquer le storytelling immédiatement ?", "options": ["Réécrire tout son site web", "Remplacer UNE statistique par UNE histoire dans son prochain contenu", "Suivre une formation de 6 mois", "Lire des romans"], "correct_index": 1, "explication": ""}], "chapitre_id": "aa561fd3-1cc5-4fd1-b0f5-0610157483a8"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Storytelling — Module 2 — Structures Narratives", "description": "25 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Qui a formalisé le Monomythe (Voyage du Héros) ?", "options": ["Dan Harmon", "Gustav Freytag", "Joseph Campbell", "Simon Sinek"], "correct_index": 2, "explication": ""}, {"question": "Combien d'étapes compte le Monomythe ?", "options": ["3", "5", "6", "8"], "correct_index": 3, "explication": ""}, {"question": "Dans le Monomythe, quelle étape correspond au moment où le héros hésite ?", "options": ["L'appel à l'aventure", "Le refus de l'appel", "Le franchissement du seuil", "L'épreuve suprême"], "correct_index": 1, "explication": ""}, {"question": "En business, qui joue le rôle du « mentor » dans le Monomythe ?", "options": ["Le client", "Le concurrent", "Vous (le prestataire/formateur)", "L'algorithme"], "correct_index": 2, "explication": ""}, {"question": "Dans la structure en 3 actes, quel pourcentage du texte doit occuper le CONFLIT ?", "options": ["25%", "33%", "50%", "75%"], "correct_index": 2, "explication": ""}, {"question": "Quel est l'acte le plus important dans la structure en 3 actes ?", "options": ["L'acte 1 (situation)", "L'acte 2 (conflit)", "L'acte 3 (résolution)", "Ils sont tous égaux"], "correct_index": 1, "explication": ""}, {"question": "Qui a créé le Story Circle ?", "options": ["Joseph Campbell", "Dan Harmon", "Pixar", "Gustav Freytag"], "correct_index": 1, "explication": ""}, {"question": "Quelle étape du Story Circle donne de la profondeur à l'histoire ?", "options": ["Il veut quelque chose", "Il obtient ce qu'il voulait", "Mais il paie le prix fort", "Il a changé"], "correct_index": 2, "explication": ""}, {"question": "Combien de phrases composent la Pixar Story Spine ?", "options": ["3", "5", "6", "8"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la force de la Pixar Story Spine ?", "options": ["Elle est longue et détaillée", "Elle force la causalité (« À cause de ça... »)", "Elle est réservée aux films d'animation", "Elle n'a pas de conflit"], "correct_index": 1, "explication": ""}, {"question": "Qui a formalisé la Pyramide en 5 actes ?", "options": ["Joseph Campbell", "Dan Harmon", "Gustav Freytag", "Christopher Vogler"], "correct_index": 2, "explication": ""}, {"question": "Dans la Pyramide de Freytag, quel est le sommet de la tension ?", "options": ["L'exposition", "L'action montante", "Le climax", "Le dénouement"], "correct_index": 2, "explication": ""}, {"question": "Quel acte de Freytag correspond au « point de non-retour » ?", "options": ["L'exposition", "L'action montante", "Le climax", "L'action descendante"], "correct_index": 1, "explication": ""}, {"question": "Combien d'actes compte la structure moderne adaptée au digital ?", "options": ["3", "4", "5", "8"], "correct_index": 1, "explication": ""}, {"question": "Dans la structure en 4 actes, quel est l'élément le plus important ?", "options": ["Le contexte", "Le conflit", "Le hook (accroche)", "La transformation"], "correct_index": 2, "explication": ""}, {"question": "Quelle structure est idéale pour les posts de réseaux sociaux courts ?", "options": ["Le Monomythe", "La Pyramide de Freytag", "Le Story Circle de Dan Harmon", "La structure en 5 actes"], "correct_index": 2, "explication": ""}, {"question": "Quel pourcentage de lecteurs s'arrêtent à la première phrase si le hook est faible ?", "options": ["30%", "50%", "65%", "80%"], "correct_index": 3, "explication": ""}, {"question": "Dans la Pixar Story Spine, que signifie « Jusqu'au jour où... » ?", "options": ["La routine", "L'élément perturbateur ou le climax", "La conclusion", "La leçon"], "correct_index": 1, "explication": ""}, {"question": "Quelle est la structure de la Pyramide de Freytag ?", "options": ["Hook → Contexte → Conflit → Transformation", "Exposition → Action montante → Climax → Action descendante → Dénouement", "Situation → Conflit → Résolution", "Zone de confort → Désir → Épreuve → Changement"], "correct_index": 1, "explication": ""}, {"question": "Dans le cas pratique de Camille (Pixar Spine), quel est l'élément déclencheur ?", "options": ["Elle a été licenciée", "Son fils lui a demandé pourquoi elle ne souriait pas le lundi", "Elle a gagné au loto", "Elle a lu un livre"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi « J'ai tout quitté et tout a marché » n'est PAS une bonne histoire ?", "options": ["C'est trop court", "Il n'y a pas de prix à payer ni de conflit", "C'est du mensonge", "Il manque un CTA"], "correct_index": 1, "explication": ""}, {"question": "Quelle structure est la plus ancienne et à la base de toutes les autres ?", "options": ["La structure en 4 actes", "Le Story Circle", "La Pyramide de Freytag", "Le Monomythe"], "correct_index": 2, "explication": ""}, {"question": "Dans la structure 4 actes digitale, quel pourcentage minimum doit occuper le conflit ?", "options": ["20%", "30%", "50%", "70%"], "correct_index": 2, "explication": ""}, {"question": "À quoi sert la « boucle narrative » dans le dénouement de Freytag ?", "options": ["À rallonger le texte", "À créer un sentiment de complétude en faisant écho au début", "À ajouter un nouveau personnage", "À créer du suspense"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi la causalité (« À cause de ça... ») rend-elle une histoire plus puissante ?", "options": ["Elle allonge le texte", "Chaque événement est la conséquence du précédent, ce qui crée une logique narrative", "Elle évite le conflit", "Elle simplifie l'histoire"], "correct_index": 1, "explication": ""}], "chapitre_id": "c6014cb1-1035-418b-b29a-b802ac811103"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Storytelling — Module 3 — Personnages & Transformation", "description": "25 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Qu'est-ce qui intéresse le lecteur dans une histoire ?", "options": ["Les événements", "Les statistiques", "Ce que les événements font RESSENTIR au personnage", "Le lieu de l'histoire"], "correct_index": 2, "explication": ""}, {"question": "Quelles sont les 3 conditions pour qu'un personnage fonctionne ?", "options": ["Beauté, intelligence, force", "Identification, empathie, enjeu", "Nom, âge, métier", "Humour, charisme, mystère"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que l'identification dans le storytelling ?", "options": ["Connaître le nom du personnage", "Le lecteur se voit dans le personnage", "Le personnage a une carte d'identité", "Le personnage est célèbre"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce qui crée l'empathie envers un personnage ?", "options": ["Sa perfection", "Sa richesse", "Sa vulnérabilité ou son courage", "Son intelligence"], "correct_index": 2, "explication": ""}, {"question": "Le vrai conflit dans un arc de transformation est...", "options": ["Extérieur (contre un ennemi)", "Financier", "Intérieur (le personnage contre lui-même)", "Politique"], "correct_index": 2, "explication": ""}, {"question": "Quel est le « moment de choix » dans l'arc de transformation ?", "options": ["Le moment où le personnage gagne de l'argent", "L'instant où le personnage décide qui il veut être", "Le moment du premier échec", "La rencontre avec le mentor"], "correct_index": 1, "explication": ""}, {"question": "Combien d'archétypes de personnages a identifié Christopher Vogler ?", "options": ["4", "6", "8", "12"], "correct_index": 2, "explication": ""}, {"question": "En business, qui est le HÉROS de votre histoire ?", "options": ["Vous", "Votre produit", "Votre client", "Votre concurrent"], "correct_index": 2, "explication": ""}, {"question": "En business, quel archétype représentez-VOUS ?", "options": ["Le Héros", "Le Mentor", "L'Ombre", "Le Farceur"], "correct_index": 1, "explication": ""}, {"question": "Quel archétype représente l'antagoniste (peurs, concurrence, système) ?", "options": ["Le Gardien du Seuil", "L'Héraut", "L'Ombre", "Le Changeant"], "correct_index": 2, "explication": ""}, {"question": "Combien d'éléments composent un personnage mémorable ?", "options": ["3", "5", "7", "10"], "correct_index": 2, "explication": ""}, {"question": "Quelle est la différence entre le DÉSIR et le BESOIN d'un personnage ?", "options": ["Il n'y en a pas", "Le désir est ce qu'il veut, le besoin est ce dont il a vraiment besoin", "Le désir est concret, le besoin est financier", "Le besoin vient avant le désir"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi un personnage doit-il avoir un DÉFAUT ?", "options": ["Pour être détestable", "Parce que le défaut crée l'identification — un personnage parfait est inintéressant", "Pour créer du conflit avec les autres personnages", "Pour justifier son échec"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que la « blessure » d'un personnage ?", "options": ["Une blessure physique", "L'événement passé qui explique ses comportements actuels", "Son plus grand regret", "Sa faiblesse physique"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi la PEUR est-elle le moteur de la tension narrative ?", "options": ["Elle rend le personnage faible", "Elle rend chaque action plus intense car le personnage agit MALGRÉ sa peur", "Elle fait fuir le lecteur", "Elle crée de l'humour"], "correct_index": 1, "explication": ""}, {"question": "Que multiplie par 10 le fait de donner un prénom à votre client type ?", "options": ["Le prix de votre offre", "L'identification", "Le nombre de mots", "La complexité"], "correct_index": 1, "explication": ""}, {"question": "Dans le cas pratique de Rayan, quel est son ENJEU ?", "options": ["Il veut une promotion", "Dans 3 mois, ses économies seront épuisées", "Il veut déménager", "Il veut plus de followers"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi « Ce programme est fait pour les coachs » est-il une version FAIBLE ?", "options": ["C'est trop court", "Il n'y a aucun personnage, donc aucune identification", "Le mot « coach » n'est pas tendance", "Il manque un prix"], "correct_index": 1, "explication": ""}, {"question": "Quel archétype apporte l'humour et la légèreté ?", "options": ["Le Mentor", "L'Allié", "Le Farceur", "L'Héraut"], "correct_index": 2, "explication": ""}, {"question": "Qu'est-ce que la « voix unique » d'un personnage ?", "options": ["Le timbre de sa voix", "Sa façon de parler, de réagir, de voir le monde", "Son accent régional", "Son slogan"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi dit-on que « le particulier touche l'universel » ?", "options": ["Les détails spécifiques rendent un personnage paradoxalement plus universel", "Il faut rester vague pour toucher tout le monde", "Le particulier est toujours meilleur", "C'est une citation célèbre sans rapport"], "correct_index": 0, "explication": ""}, {"question": "Un personnage qui ne change pas a-t-il un arc de transformation ?", "options": ["Oui, l'arc est statique", "Non, la transformation EST le cœur de l'histoire", "Oui, tant qu'il y a du conflit", "Ça dépend du contexte"], "correct_index": 1, "explication": ""}, {"question": "Quel archétype représente « celui qui annonce le changement » ?", "options": ["Le Mentor", "L'Héraut", "Le Gardien du Seuil", "L'Allié"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi l'erreur de se positionner comme le HÉROS (au lieu du mentor) est-elle fatale ?", "options": ["Parce que c'est prétentieux", "Parce que le client n'a plus de place dans votre histoire", "Parce que ça coûte plus cher", "Parce que c'est illégal"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce qui rend le personnage de Rayan « à moitié vendu » ?", "options": ["Son prix bas", "Le fait que le client se reconnaisse en lui (identification)", "Sa publicité", "Son réseau"], "correct_index": 1, "explication": ""}], "chapitre_id": "a64567be-152a-4d7c-84de-0b46e6750cbe"}$quiz$::jsonb);
SELECT public.import_quiz_from_json($quiz${"titre": "Quiz Storytelling — Module 4 — Techniques Narratives Avancées", "description": "25 questions. Valide ce quiz pour débloquer la suite de la formation.", "max_errors": 3, "status": "published", "questions": [{"question": "Sans quoi il n'y a pas d'histoire ?", "options": ["Sans personnage", "Sans conflit", "Sans happy end", "Sans dialogue"], "correct_index": 1, "explication": ""}, {"question": "Quel est le type de conflit le plus puissant en storytelling personnel ?", "options": ["Homme vs Homme", "Homme vs Nature", "Homme vs Lui-même", "Homme vs Société"], "correct_index": 2, "explication": ""}, {"question": "Que provoque le suspense dans le cerveau ?", "options": ["De l'ennui", "La libération de cortisol qui maintient l'attention", "De la confusion", "Du sommeil"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que la technique de la « promesse non tenue » ?", "options": ["Mentir au lecteur", "Annoncer quelque chose en début d'histoire et retarder la réponse", "Promettre un cadeau", "Faire une fausse promesse marketing"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que « l'horloge » en tension narrative ?", "options": ["Un objet dans l'histoire", "Un délai ou une deadline qui approche et crée de l'urgence", "Le rythme de lecture", "Le temps de publication"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que l'ironie dramatique ?", "options": ["Quand le personnage fait des blagues", "Quand le lecteur sait quelque chose que le personnage ne sait pas", "Quand l'histoire est ironique", "Quand le narrateur est sarcastique"], "correct_index": 1, "explication": ""}, {"question": "Que transforment les détails sensoriels dans une histoire ?", "options": ["Une histoire en poème", "Une histoire abstraite en expérience vécue", "Une histoire courte en histoire longue", "Une histoire triste en histoire joyeuse"], "correct_index": 1, "explication": ""}, {"question": "Quels sens sont « très puissants par surprise » car rarement utilisés ?", "options": ["Vue et ouïe", "Toucher et vue", "Odorat et goût", "Ouïe et toucher"], "correct_index": 2, "explication": ""}, {"question": "Comment créer du rythme narratif ?", "options": ["Écrire uniquement des phrases longues", "Alterner phrases courtes (choc) et longues (contexte)", "Utiliser toujours le même tempo", "Éviter les pauses"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce qu'un retournement (twist) ?", "options": ["Un changement de sujet", "Une information nouvelle qui change la signification de ce qu'on vient de lire", "Un saut dans le temps", "Un changement de narrateur"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce qu'un cliffhanger ?", "options": ["Une fin heureuse", "Finir sur une tension non résolue pour forcer la continuation", "Un début in medias res", "Un dialogue choc"], "correct_index": 1, "explication": ""}, {"question": "Quelle est la RÈGLE N°1 de l'écriture narrative ?", "options": ["Écrire long", "Show, Don't Tell (Montrer, ne pas dire)", "Toujours commencer par le début", "Utiliser des adjectifs"], "correct_index": 1, "explication": ""}, {"question": "« Il était nerveux » est un exemple de...", "options": ["Show", "Tell", "Dialogue", "Description sensorielle"], "correct_index": 1, "explication": ""}, {"question": "« Ses doigts tambourinaient sur la table » est un exemple de...", "options": ["Tell", "Show", "Métaphore", "Exagération"], "correct_index": 1, "explication": ""}, {"question": "Comment reconnaître le « Show » ?", "options": ["C'est toujours plus long", "Si on peut le voir dans une photo, c'est du Show", "C'est toujours au passé", "C'est toujours au présent"], "correct_index": 1, "explication": ""}, {"question": "Combien d'échanges de dialogue maximum dans un texte court ?", "options": ["1", "2-3", "5-6", "10+"], "correct_index": 1, "explication": ""}, {"question": "Pourquoi le dialogue accélère-t-il le rythme ?", "options": ["Il prend moins de place", "Il crée de la proximité et rend la scène vivante", "Il est plus facile à lire", "Il est toujours drôle"], "correct_index": 1, "explication": ""}, {"question": "Quel effet psychologique empêche le cerveau d'oublier une histoire inachevée ?", "options": ["L'effet placebo", "L'effet Zeigarnik", "L'effet papillon", "L'effet Dunning-Kruger"], "correct_index": 1, "explication": ""}, {"question": "Dans le cas pratique, pourquoi « 2h34 du matin » est-il plus puissant que « tard le soir » ?", "options": ["C'est plus précis", "Le détail concret active les zones sensorielles et ancre l'histoire dans le réel", "C'est plus dramatique", "Ça fait plus professionnel"], "correct_index": 1, "explication": ""}, {"question": "Qu'est-ce que la technique du « Et pourtant / Mais » ?", "options": ["Chaque étape finit par une tension non résolue", "On commence toujours par « Et pourtant »", "On utilise « mais » à chaque phrase", "On contredit le lecteur"], "correct_index": 0, "explication": ""}, {"question": "Pourquoi « Il avait très peur » est-il à éviter ?", "options": ["C'est grammaticalement incorrect", "C'est du Tell — une étiquette émotionnelle qui ne fait rien ressentir", "C'est trop court", "C'est trop négatif"], "correct_index": 1, "explication": ""}, {"question": "Quel type de conflit correspond au « syndrome de l'imposteur » ?", "options": ["Homme vs Société", "Homme vs Nature", "Homme vs Lui-même", "Homme vs Destin"], "correct_index": 2, "explication": ""}, {"question": "Pourquoi un twist crée-t-il un souvenir durable ?", "options": ["Il est toujours drôle", "Il active un pic de dopamine — le cerveau adore les surprises", "Il allonge l'histoire", "Il confond le lecteur"], "correct_index": 1, "explication": ""}, {"question": "Que signifie « Moins = Plus » en storytelling ?", "options": ["Écrire le moins possible", "Un seul détail physique bien choisi transmet plus d'émotion que 10 lignes de description", "Publier moins souvent", "Avoir moins de personnages"], "correct_index": 1, "explication": ""}, {"question": "« Sa voix s'est brisée à la deuxième phrase » — combien de mots pour transmettre une émotion entière ?", "options": ["C'est impossible en si peu de mots", "9 mots suffisent quand c'est du Show", "Il faudrait au moins 50 mots", "C'est du Tell, pas du Show"], "correct_index": 1, "explication": ""}], "chapitre_id": "a7877285-3927-4ebd-9815-039c17b5987b"}$quiz$::jsonb);
